import random
import time

def call_with_backoff(fn, max_retries=5):
    for attempt in range(max_retries):
        try:
            return fn()
        except RateLimitError as e:  # your client's 429 exception
            if attempt == max_retries - 1:
                raise
            # honor Retry-After if provided, else exponential + jitter
            wait = getattr(e, "retry_after", None) or (2 ** attempt)
            wait += random.uniform(0, 0.5)  # jitter avoids thundering herd
            print(f"429; retrying in {wait:.1f}s")
            time.sleep(wait)

class RateLimitError(Exception):
    retry_after = None
